mapper.select:
SELECT sm.permission FROM mk_sys_menu AS sm LEFT JOIN mk_sys_role_menu AS srm ON sm.id = srm.menu_id WHERE sm.is_delete = 0 AND srm.role_id IN
#{item}
GROUP BY sm.id

SELECT `id`, `name`, `permission`, `keep_alive`, `type`, `parent_id` AS pid FROM `mk_sys_menu` WHERE `is_delete` = 0
AND `parent_id` = #{parentId}
AND `keep_alive` = 0 AND `type` IN (-1, 0, 1)
